// src/components/ProjectorSearch.js
import React, { useState } from "react";
import axios from "axios";
import "./ProjectorSearch.css";

const ProjectorSearch = ({ goBack }) => {
  const [selectedDay, setSelectedDay] = useState("Monday");
  const [selectedPeriod, setSelectedPeriod] = useState(1);
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleSearch = async () => {
    setLoading(true);
    setError("");
    setResults(null);
    
    try {
      // API call to fetch available projector rooms for the selected day & period
      const response = await axios.get("/api/classrooms", {
        params: {
          projector: true,
          day: selectedDay,
          period: selectedPeriod
        }
      });

      if (response.data.length === 0) {
        setError("No projector-equipped rooms found for the selected time.");
      } else {
        setResults(response.data);
      }
    } catch (error) {
      console.error("Error fetching projector data:", error);
      setError("Failed to fetch data. Try again later.");
    }

    setLoading(false);
  };

  return (
    <div className="projector-search">
      <h2>📽 Projector Room Search</h2>

      <div className="filters">
        <label>Select Day:</label>
        <select value={selectedDay} onChange={(e) => setSelectedDay(e.target.value)}>
          {["Monday", "Tuesday", "Wednesday", "Thursday", "Friday"].map((day) => (
            <option key={day} value={day}>{day}</option>
          ))}
        </select>

        <label>Select Period:</label>
        <select value={selectedPeriod} onChange={(e) => setSelectedPeriod(Number(e.target.value))}>
          {[1, 2, 3, 4, 5, 6, 7, 8].map((period) => (
            <option key={period} value={period}>Period {period}</option>
          ))}
        </select>
      </div>

      <div className="button-group">
        <button onClick={handleSearch} disabled={loading}>
          {loading ? "Searching..." : "Search"}
        </button>
        <button onClick={goBack}>Back</button>
      </div>

      {error && <p className="error">{error}</p>}

      {results && (
        <div className="results">
          <h3>Available Projector Rooms:</h3>
          <table>
            <thead>
              <tr>
                <th>Room</th>
                <th>Faculty</th>
                <th>Subject</th>
                <th>Year</th>
                <th>Section</th>
              </tr>
            </thead>
            <tbody>
              {results.map((room, index) => (
                <tr key={index}>
                  <td>{room.room}</td>
                  <td>{room.faculty || "Unknown"}</td>
                  <td>{room.subject}</td>
                  <td>{room.year}</td>
                  <td>{room.section}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default ProjectorSearch;
